            "title": "Anaerobic Bacteriology",
            "gdoc": "https://docs.google.com/document/d/10R_e4wShmMViU4ZVSB8Q3KayM5qTLdn4JEvl1ooqlfQ/edit?usp=sharing",
            "nlm": "https://notebooklm.google.com/notebook/3c30078b-b650-4ed8-b1a9-283f5bb2a4b6"
